#include <iostream>
#include <vector>
#include <queue>
#include <set>

using namespace std;

bool isValidHeap(vector<int> &arr)
{
    priority_queue<int, vector<int>, greater<int>> heap;
    set<int> uniquenessSet;
    for (int num : arr) {
        if (uniquenessSet.find(num) != uniquenessSet.end()) {
            return false;
        }
        uniquenessSet.insert(num);
        heap.push(num);
    }
    return true;
}

int main() {
    int n;
    cin >> n;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) {
        cin >> arr[i];
    }
    bool isValid = isValidHeap(arr);
    if (isValid) {
        cout << "1" << endl;
    } else {
        cout << "-1" << endl;
    }
    return 0;
}
